blocks.body:
{
    "level": "B2",
    "intro": "W tym temacie poznasz <strong>bezosobowy/report pasywny</strong> - konstrukcje formalne służące do przekazywania myśli, wiadomości, plotek: <strong>Mówi się, że...</strong>, <strong>Uważa się, że...</strong>.",
    "rules": [
        {
            "label": "Bezosobowy",
            "color": "emerald",
            "text": "Konstrukcja bezosobowa: <strong>Mówi się/uważa się, że...</strong>",
            "example": "It is said that he is very rich."
        },
        {
            "label": "Osobisty",
            "color": "blue",
            "text": "Konstrukcja osobista: <strong>Mówi się/uważa się, że...</strong>",
            "example": "He is said to be very rich."
        },
        {
            "label": "Styl",
            "color": "rose",
            "text": "Styl formalny: wiadomości, nauka, teksty oficjalne",
            "example": "It is reported that the talks have failed."
        }
    ]
}

{
    "title": "1. Konstrukcja bezosobowa: Mówi się/uważa się, że...",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>To + jest/było + V3 (czasownik zgłaszający) + tamto + klauzula</strong>",
            "examples": [
                {
                    "en": "Active: People say that he is very rich.",
                    "ua": "Ludzie mówią, że jest bardzo bogaty."
                },
                {
                    "en": "Passive: It is said that he is very rich.",
                    "ua": "Mówią, że jest bardzo bogaty."
                }
            ]
        },
        {
            "label": "Wierzy się",
            "color": "sky",
            "description": "Aby przekazać <strong>przekonania, opinie</strong>.",
            "examples": [
                {
                    "en": "It is believed that the universe is expanding.",
                    "ua": "Uważa się, że wszechświat się rozszerza."
                },
                {
                    "en": "It was believed that the Earth was flat.",
                    "ua": "Wierzono, że Ziemia jest płaska."
                }
            ]
        },
        {
            "label": "Poinformowano",
            "color": "blue",
            "description": "Aby przesyłać <strong>wiadomości, wiadomości</strong>.",
            "examples": [
                {
                    "en": "It is reported that the storm is approaching.",
                    "ua": "Według doniesień zbliża się burza."
                },
                {
                    "en": "It was reported that the talks had failed.",
                    "ua": "Poinformowano, że negocjacje zakończyły się niepowodzeniem."
                }
            ]
        },
        {
            "label": "Wiadomo",
            "color": "amber",
            "description": "Aby przekazać <strong>powszechnie znane fakty</strong>.",
            "examples": [
                {
                    "en": "It is known that smoking causes cancer.",
                    "ua": "Wiadomo, że palenie powoduje raka."
                },
                {
                    "en": "It is widely known that she is an expert.",
                    "ua": "Powszechnie wiadomo, że jest ekspertem."
                }
            ]
        }
    ]
}

{
    "title": "2. Konstrukcja osobista: Mówi się/uważa się, że...",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "<strong>Podmiot + jest/był + V3 + do + bezokolicznik</strong>",
            "examples": [
                {
                    "en": "Active: People say that he is very rich.",
                    "ua": "Ludzie mówią, że jest bardzo bogaty."
                },
                {
                    "en": "Passive: He is said to be very rich.",
                    "ua": "Mówią, że jest bardzo bogaty."
                }
            ]
        },
        {
            "label": "Bieżące działania",
            "color": "sky",
            "description": "<strong>do + bezokolicznik</strong> — gdy akcja następuje jednocześnie z momentem mowy.",
            "examples": [
                {
                    "en": "She is believed to live in Paris.",
                    "ua": "Uważa się, że mieszka w Paryżu."
                },
                {
                    "en": "He is thought to be the best candidate.",
                    "ua": "Uważa się, że jest to najlepszy kandydat."
                }
            ]
        },
        {
            "label": "Przeszłe działania",
            "color": "blue",
            "description": "<strong>mieć + V3</strong> – gdy akcja miała miejsce wcześniej.",
            "examples": [
                {
                    "en": "She is believed to have left the country.",
                    "ua": "Uważa się, że opuściła kraj."
                },
                {
                    "en": "He is said to have written many books.",
                    "ua": "Mówi się, że napisał wiele książek."
                }
            ]
        },
        {
            "label": "Trwające działania",
            "color": "amber",
            "description": "<strong>być + V-ing</strong> – gdy akcja trwa.",
            "examples": [
                {
                    "en": "They are reported to be negotiating.",
                    "ua": "Według doniesień prowadzą rozmowy."
                },
                {
                    "en": "He is believed to be working on a new project.",
                    "ua": "Uważa się, że pracuje nad nowym projektem."
                }
            ]
        }
    ]
}

{
    "title": "3. Typowe czasowniki reportażowe",
    "sections": [
        {
            "label": "powiedzieć / powiedzieć",
            "color": "emerald",
            "description": "<strong>powiedz</strong> — w przypadku stwierdzeń ogólnych. <strong>powiedz</strong> – rzadziej w formie bezosobowej.",
            "examples": [
                {
                    "en": "It is said that he resigned.",
                    "ua": "Mówią, że zrezygnował."
                },
                {
                    "en": "He is said to have resigned.",
                    "ua": "Mówią, że zrezygnował."
                }
            ]
        },
        {
            "label": "wierzyć/myśleć",
            "color": "blue",
            "description": "<strong>wierz, myśl</strong> — dla myśli i przekonań.",
            "examples": [
                {
                    "en": "It is believed that the plan will work.",
                    "ua": "Uważa się, że plan się powiódł."
                },
                {
                    "en": "She is thought to be an expert.",
                    "ua": "Uważana jest za ekspertkę."
                }
            ]
        },
        {
            "label": "zgłosić/ogłosić",
            "color": "sky",
            "description": "<strong>zgłoś, ogłoś</strong> — w przypadku oficjalnych ogłoszeń.",
            "examples": [
                {
                    "en": "It was reported that 50 people were injured.",
                    "ua": "Ze wstępnych informacji wynika, że ​​rannych zostało 50 osób."
                },
                {
                    "en": "The company is reported to be closing.",
                    "ua": "Pojawiła się informacja, że ​​firma jest zamykana."
                }
            ]
        },
        {
            "label": "oczekiwać / przypuszczać",
            "color": "amber",
            "description": "<strong>oczekiwać, zakładać, rozważać</strong> — w przypadku oczekiwań i założeń.",
            "examples": [
                {
                    "en": "It is expected that prices will rise.",
                    "ua": "Oczekuje się, że ceny wzrosną."
                },
                {
                    "en": "She is supposed to arrive at 5.",
                    "ua": "Powinna przyjechać o 5:00."
                },
                {
                    "en": "He is considered to be a genius.",
                    "ua": "Uważany jest za geniusza."
                }
            ]
        },
        {
            "label": "wiedzieć/rozumieć",
            "color": "rose",
            "description": "<strong>wiedzieć, rozumieć</strong> — dla faktów i zrozumienia.",
            "examples": [
                {
                    "en": "It is known that water boils at 100°C.",
                    "ua": "Wiadomo, że woda wrze w temperaturze 100°C."
                },
                {
                    "en": "He is understood to have accepted the offer.",
                    "ua": "Wiadomo, że przyjął tę propozycję."
                }
            ]
        }
    ]
}

{
    "title": "4. Bezosobowy a osobisty pasywny",
    "intro": "Obie konstrukcje mają to samo znaczenie, ale z innym naciskiem:",
    "rows": [
        {
            "en": "It is said that he is rich.",
            "ua": "Bezosobowy (struktura It)",
            "note": "Skup się na faktach, neutralnie."
        },
        {
            "en": "He is said to be rich.",
            "ua": "Osobiste (struktura przedmiotowa)",
            "note": "Krótko mówiąc, skoncentruj się na osobie."
        },
        {
            "en": "It is believed that she left.",
            "ua": "Bezosobowy",
            "note": "She is believed to have left."
        },
        {
            "en": "It was reported that they won.",
            "ua": "Bezosobowy",
            "note": "They were reported to have won."
        }
    ],
    "warning": "📌 Konstrukcja osobista często brzmi <strong>bardziej naturalnie</strong> we współczesnym języku angielskim."
}

{
    "title": "5. Transformacja: Aktywna → Pasywna",
    "sections": [
        {
            "label": "Krok 1",
            "color": "emerald",
            "description": "Wskaż czasownik główny (powiedz, wierz, pomyśl...) i zdanie podrzędne.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "Ludzie = podmiot ogólny, powiedz = czasownik, że... = zdanie"
                }
            ]
        },
        {
            "label": "Krok 2: Struktura IT",
            "color": "sky",
            "description": "Utwórz <strong>To</strong> podmiot + jest/był + V3 + ta klauzula.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "→ Mówi się, że jest geniuszem."
                }
            ]
        },
        {
            "label": "Krok 3: Struktura przedmiotowa",
            "color": "blue",
            "description": "Niech podmiot zdania podrzędnego będzie głównym + is/was + V3 + do-bezokolicznika.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "→ Mówi się, że jest geniuszem."
                },
                {
                    "en": "People believed that she had left.",
                    "ua": "→ Uważano, że odeszła."
                }
            ]
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie „to” przed bezokolicznikiem.",
            "wrong": "He is said be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Napięte zamieszanie: przeszłe działania z prostym bezokolicznikiem.",
            "wrong": "She is believed to leave yesterday.",
            "right": "✅ She is believed to have left yesterday."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie „tego” w strukturze podmiotu.",
            "wrong": "He is said that to be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Pominięcie „tego” w strukturze It.",
            "wrong": "It is said he is rich.",
            "right": "✅ It is said that he is rich."
        }
    ]
}
